import { clockWipe as remotionClockWipe, type ClockWipeProps as RemotionClockWipeProps } from '@remotion/transitions/clock-wipe';
import type { TransitionPresentation } from '@remotion/transitions';
import { clockWipeSchema, type ClockWipeOptions } from './schema';

export { clockWipeSchema, type ClockWipeOptions };

/**
 * A clock-hand wipe — the boundary between scenes rotates around the
 * canvas center like a sweeping clock hand. Distinctive and a little
 * cinematic; use sparingly so it stays "deliberate" rather than gimmicky.
 *
 * **Requires `width` + `height`** — pass them from `useVideoConfig()` in
 * the surrounding scene (Remotion's clock-wipe needs explicit dimensions
 * to compute the rotating clip path).
 *
 * Pair with the recommended Onda timing for the house feel:
 * `linearTiming({ durationInFrames: 18, easing: Easing.bezier(0.16, 1, 0.3, 1) })`
 *
 * Wraps Remotion's `clockWipe()`.
 */
export function clockWipe(
  options: ClockWipeOptions,
): TransitionPresentation<RemotionClockWipeProps> {
  const opts = clockWipeSchema.parse(options);
  return remotionClockWipe({ width: opts.width, height: opts.height });
}

export default clockWipe;

import { z } from 'zod';

/** Zod schema for {@link clockWipe} options. */
export const clockWipeSchema = z.object({
  /** Discriminator literal — matches this entry's registry slug. Auto-populated when omitted (`schema.parse({})` works as before). Lets consumers build `z.discriminatedUnion('kind', [...])` directly over onda schemas. */
  kind: z.literal('clock-wipe').default('clock-wipe'),
  /** Canvas width in px — typically `useVideoConfig().width`. Required by Remotion's clock wipe. */
  width: z.number().int().positive(),
  /** Canvas height in px — typically `useVideoConfig().height`. */
  height: z.number().int().positive(),
});

export type ClockWipeOptions = z.input<typeof clockWipeSchema>;

# clockWipe

A clock-hand wipe — the boundary between scenes rotates around the canvas center like a sweeping clock hand. Distinctive; use sparingly so it stays "deliberate" rather than gimmicky.

## Options

| Name | Type | Required | Notes |
| --- | --- | --- | --- |
| `width` | `integer > 0` | ✓ | Canvas width in px. Typically `useVideoConfig().width`. |
| `height` | `integer > 0` | ✓ | Canvas height in px. Typically `useVideoConfig().height`. |

## Usage

```tsx
import { Easing, useVideoConfig } from 'remotion';
import { TransitionSeries, linearTiming } from '@remotion/transitions';
import { clockWipe } from './components/onda/transitions/clock-wipe/clockWipe';

const MyScene = () => {
  const { width, height } = useVideoConfig();
  return (
    <TransitionSeries>
      <TransitionSeries.Sequence durationInFrames={150}>
        <Scene1 />
      </TransitionSeries.Sequence>
      <TransitionSeries.Transition
        presentation={clockWipe({ width, height })}
        timing={linearTiming({
          durationInFrames: 18,
          easing: Easing.bezier(0.16, 1, 0.3, 1),
        })}
      />
      <TransitionSeries.Sequence durationInFrames={150}>
        <Scene2 />
      </TransitionSeries.Sequence>
    </TransitionSeries>
  );
};
```

## Composition notes

- **Width / height are required.** Remotion's `clockWipe()` needs explicit dimensions to compute the rotating clip path. Always pass them from `useVideoConfig()` in the surrounding component.
- **Use sparingly.** The clock-hand sweep is a strong visual; if every cut uses it, scenes start to feel like a slideshow. Reserve for genuine "time passes" or "change of state" moments.
- **House timing applies** — pair with `linearTiming({ durationInFrames: 18, easing: Easing.bezier(0.16, 1, 0.3, 1) })` for the standard rhythm.
